For some tests it would be helpful to "receive" fake emails. How would you do that for the following function?

def receive_emails(self) -> None:
        """Empfangen der Antwort-Emails und updaten der zugehörigen Log-Einträge."""
        # Holt sich eine Referenz auf die Inbox
        mailbox = self.account.mailbox()
        inbox = mailbox.inbox_folder()

        # Erstell Suchbefehl der nur ungelesene Emails nach ihrem Datum sortiert abfragt
        query = inbox.new_query().on_attribute("isRead").equals(False)
        query.order_by("receivedDateTime", ascending=True)

        # Pagination über den Suchbefehl
        for message in inbox.get_messages(query=query, limit=25):
            # Trenne den Betreff in seine Bestandteile
            subject_value_array = str(message.subject).split(" ")
            # Überprüfe ob der Betreff aus 7 Teilen besteht
            if len(subject_value_array) != 7:
                self.handle_invalid_incoming_email(
                    message, "Ungültiger Betreff - erwartetes Format: 7 Elemente."
                )
                continue
            # Extrahiere die Log-Id
            log_id = subject_value_array[2]
            if len(log_id) != 36:
                self.handle_invalid_incoming_email(
                    message, "Fehlerhafte Log-ID - Erwartet eine UUID mit 36 Zeichen."
                )
                continue

            # Extrahiere den Email-Typen
            reply_from_message_type = subject_value_array[3]
            if not (reply_from_message_type in ["reminder", "error", "init"]):
                self.handle_invalid_incoming_email(
                    message,
                    "Ungültiger Nachrichtentyp. Erlaubt: reminder, error, init.",
                )
                continue
            updates: dict = {}
            # Extrahiere die vom Nutzer gewählte Option
            option_code: int = 0
            try:
                option_code = int(subject_value_array[1])
            except:
                self.handle_invalid_incoming_email(
                    message, "Optionscode ist keine Ganzzahl."
                )
                continue
            code_key = None
            # Option: suche den Key, der zu option_code passt
            for key, state_date in self.option_codes.items():
                if state_date == option_code:
                    code_key = key
                    break
            # Erstelle Objekt mit den zu speichernden Updates je nach gewählter Option
            if code_key in self.option_mapping:
                state, date_field = self.option_mapping[code_key]
                updates = {
                    "status": state,
                    "kommentar": str(message.get_body_text()),
                    date_field: datetime.now(ZoneInfo("Europe/Berlin")),
                }
            else:
                self.handle_invalid_incoming_email(message, "Unbekannter Optionscode.")
                continue

            # Lade den Log-Eintrag anhand der extrahierten Id
            corresponding_log_entry = self.logging_controller.get_entry(log_id)
            if corresponding_log_entry == None:
                self.handle_invalid_incoming_email(
                    message, f"Log-Eintrag {log_id} existiert nicht."
                )
                continue

            # Speicher den letzten "In Bearbeitungs"-Zustand um die abgeschlossenen Log-Einträge aussagekräftiger zu machen
            if updates["status"] == State.COMPLETED:
                updates["letzter_bearbeitungs_status"] = corresponding_log_entry.status

            # Überprüfung ob der Log-Eintrag wieder geöffnet wird
            if (
                corresponding_log_entry.status == State.COMPLETED
                and updates["status"] != State.COMPLETED
            ):
                self.handle_invalid_incoming_email(
                    message,
                    f"Versuch, abgeschlossenen Log-Eintrag {log_id} wieder zu öffnen.",
                )
                continue

            # Update des Log-Eintrags
            if self.logging_controller.update_entry(log_id, updates=updates):
                logging.emailalert(
                    f'Log-Eintrag mit der ID {log_id} wurde erfolgreich aktualisiert. Neuer Status: "{updates["status"].value}". Kommentar: "{updates["kommentar"]}". Berater: {corresponding_log_entry.berater_vorname} {corresponding_log_entry.berater_nachname}.'
                )
            else:
                logging.info(
                    f"Aktualisierung des Log-Eintrags mit der ID {log_id} ist fehlgeschlagen."
                )

